commits.content:
.slickDots {
  position: absolute;
  bottom: 10px; 
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  justify-content: center;
  align-items: center;
  list-style: none;
  padding: 0;
  margin: 0;
  z-index: 10;
}

.slickDot,
.slickDotActive {
  width: 12px; 
  height: 12px; 
  margin: 0 5px; 
  background-color: rgba(255, 255, 255, 0.5); 
  border-radius: 50%; 
  cursor: pointer;
  transition: background-color 0.3s ease; 
  border: none; 
}

.slickDotActive {
  background-color: #FF8C00; 
}


.slickDot:hover {
  background-color: rgba(255, 255, 255, 0.8); 
}

.slickDotActive:hover {
  background-color: #FFA500; 
}
